class Solution:
    def distMoney(self, money, children):
        NEG = float('-inf')
        dp = [[NEG] * (money + 1) for _ in range(children + 1)]
        dp[0][0] = 0
        for c in range(1, children + 1):
            for m in range(c, money + 1):
                best = NEG
                for v in range(1, m + 1):
                    if v == 4:
                        continue
                    prev = dp[c - 1][m - v]
                    if prev == NEG:
                        continue
                    cand = prev + (1 if v == 8 else 0)
                    if cand > best:
                        best = cand
                dp[c][m] = best
        return dp[children][money] if dp[children][money] != NEG else -1

