class Solution:
    def distMoney(self, money, children):
        if money < children:
            return -1
        k = min(children, money // 8)
        while k >= 0:
            rem_money = money - 8 * k
            rem_kids = children - k
            if rem_kids == 0:
                if rem_money == 0:
                    return k
            elif rem_money >= rem_kids and not (rem_kids == 1 and rem_money == 4):
                return k
            k -= 1
        return -1

